class Node {
public:
    int key, value, count;
    Node(int k, int v, int c) : key(k), value(v), count(c) {}
};

class LFUCache {
private:
    int capacity;
    unordered_map<int, Node*> keyNode;
    unordered_map<int, list<Node*>> countList;
    int minCount;

public:
    LFUCache(int capacity) {
        this->capacity = capacity;
        minCount = 0;
    }

    int get(int key) {
        if (capacity == 0) return -1;
        if (keyNode.find(key) == keyNode.end()) return -1;

        Node* node = keyNode[key];
        countList[node->count].remove(node);

        if (minCount == node->count && countList[minCount].empty()) {
            minCount++;
        }

        node->count++;
        countList[node->count].push_back(node);

        return node->value;
    }

    void put(int key, int value) {
        if (capacity == 0) return;

        if (keyNode.find(key) != keyNode.end()) {
            Node* node = keyNode[key];
            node->value = value;
            countList[node->count].remove(node);

            if (minCount == node->count && countList[minCount].empty()) {
                minCount++;
            }

            node->count++;
            countList[node->count].push_back(node);
            return;
        }

        if (keyNode.size() == capacity) {
            Node* front = countList[minCount].front();
            countList[minCount].pop_front();
            keyNode.erase(front->key);
            delete front;
        }

        Node* newNode = new Node(key, value, 1);
        keyNode[key] = newNode;
        countList[1].push_back(newNode);
        minCount = 1;
    }
};
